{
  "query": "query GetPost($id: ID!) { post(id: $id) { id title content insertedAt updatedAt topics { id name } } }",
  "variables": { "id": "abc123" }
}

{
  "query": "query GetOrganizationPosts($first: Int!, $after: String) { posts(first: $first, after: $after) { edges { node { id title insertedAt updatedAt } cursor } pageInfo { hasNextPage endCursor } } }",
  "variables": { "first": 50, "after": null }
}

{
  "query": "query SearchPosts($query: String!, $first: Int!) { search(query: $query, first: $first) { edges { node { id title } } pageInfo { hasNextPage endCursor } } }",
  "variables": { "query": "onboarding", "first": 25 }
}

{
  "query": "mutation UpdatePostContent($id: ID!, $content: JSON!) { updatePost(id: $id, content: $content) { id version updatedAt } }",
  "variables": { "id": "abc123", "content": { "ops": [ { "insert": "Hello world\n" } ] } }
}

{
  "query": "query GetTopicPosts($id: ID!) { topic(id: $id) { id name posts(first: 50) { edges { node { id title } } pageInfo { hasNextPage endCursor } } } }",
  "variables": { "id": "topic123" }
}

{
  "query": "query GetTopics($first: Int!, $after: String) { topics(first: $first, after: $after) { edges { node { id name description } } pageInfo { hasNextPage endCursor } } }",
  "variables": { "first": 50, "after": null }
}

{
  "query": "query GetUser($id: ID!) { user(id: $id) { id name email } }",
  "variables": { "id": "user123" }
}
